const fs = require('fs');
const path = require('path');

const { place_id, industry, photos_refs = [], output_dir } = $input.first().json.body;
const dir = output_dir || `/data/assets/${place_id}`;

// Ensure directory exists
fs.mkdirSync(dir, { recursive: true });
fs.mkdirSync(path.join(dir, 'originals'), { recursive: true });
fs.mkdirSync(path.join(dir, 'optimized'), { recursive: true });

const downloaded = [];
const apiKey = process.env.GOOGLE_API_KEY || $env.GOOGLE_API_KEY;

for (let i = 0; i < photos_refs.length; i++) {
  const ref = photos_refs[i];
  try {
    const url = `https://places.googleapis.com/v1/${ref}/media?maxHeightPx=1200&maxWidthPx=1600&key=${apiKey}`;
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url,
      encoding: 'arraybuffer',
      returnFullResponse: true
    });

    const filename = `photo_${i}.jpg`;
    const filepath = path.join(dir, 'originals', filename);
    fs.writeFileSync(filepath, Buffer.from(response.body));
    downloaded.push({ index: i, filename, filepath, source: 'google_maps' });
  } catch (err) {
    downloaded.push({ index: i, error: err.message, source: 'google_maps' });
  }
}

return [{
  json: {
    place_id,
    industry,
    output_dir: dir,
    photos_refs,
    downloaded,
    downloaded_count: downloaded.filter(d => !d.error).length,
    needs_unsplash: downloaded.filter(d => !d.error).length < 3
  }
}];

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const { place_id, industry, output_dir, downloaded_count, needs_unsplash } = data;

let unsplash_photos = [];

if (needs_unsplash) {
  const needed = Math.max(0, 3 - downloaded_count);
  const unsplashKey = process.env.UNSPLASH_ACCESS_KEY || $env.UNSPLASH_ACCESS_KEY || '';

  if (unsplashKey && needed > 0) {
    try {
      const searchUrl = `https://api.unsplash.com/search/photos?query=${encodeURIComponent(industry)}&per_page=${needed}&orientation=landscape`;
      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: searchUrl,
        headers: { 'Authorization': `Client-ID ${unsplashKey}` }
      });

      const results = response.results || [];
      for (let i = 0; i < results.length; i++) {
        const photo = results[i];
        try {
          const imgResponse = await this.helpers.httpRequest({
            method: 'GET',
            url: photo.urls.regular,
            encoding: 'arraybuffer',
            returnFullResponse: true
          });

          const filename = `unsplash_${i}.jpg`;
          const filepath = path.join(output_dir, 'originals', filename);
          fs.writeFileSync(filepath, Buffer.from(imgResponse.body));
          unsplash_photos.push({
            index: i,
            filename,
            filepath,
            source: 'unsplash',
            credit: photo.user?.name || 'Unsplash',
            unsplash_id: photo.id
          });
        } catch (e) {
          unsplash_photos.push({ index: i, error: e.message, source: 'unsplash' });
        }
      }
    } catch (err) {
      unsplash_photos.push({ error: 'Unsplash search failed: ' + err.message });
    }
  }
}

return [{
  json: {
    ...data,
    unsplash_photos,
    total_photos: downloaded_count + unsplash_photos.filter(p => !p.error).length
  }
}];

const fs = require('fs');
const path = require('path');
const Vibrant = require('node-vibrant');

const data = $input.first().json;
const { output_dir } = data;
const originalsDir = path.join(output_dir, 'originals');

let brandColors = {
  primary: '#1a73e8',
  secondary: '#174ea6',
  accent: '#ea4335',
  background: '#ffffff',
  text: '#202124'
};

try {
  const files = fs.readdirSync(originalsDir).filter(f => f.endsWith('.jpg') || f.endsWith('.png'));

  if (files.length > 0) {
    const firstImage = path.join(originalsDir, files[0]);
    const palette = await Vibrant.from(firstImage).getPalette();

    brandColors = {
      primary: palette.Vibrant?.hex || '#1a73e8',
      secondary: palette.DarkVibrant?.hex || '#174ea6',
      accent: palette.LightVibrant?.hex || '#ea4335',
      background: palette.LightMuted?.hex || '#ffffff',
      text: palette.DarkMuted?.hex || '#202124'
    };
  }
} catch (err) {
  // Keep defaults on error
}

// Write brand-colors.json
fs.writeFileSync(
  path.join(output_dir, 'brand-colors.json'),
  JSON.stringify(brandColors, null, 2)
);

return [{ json: { ...data, brand_colors: brandColors } }];

const fs = require('fs');
const path = require('path');
const sharp = require('sharp');

const data = $input.first().json;
const { output_dir } = data;
const originalsDir = path.join(output_dir, 'originals');
const optimizedDir = path.join(output_dir, 'optimized');

const variants = [
  { suffix: 'hero', width: 1920, height: 1080 },
  { suffix: 'card', width: 640, height: 480 },
  { suffix: 'thumb', width: 320, height: 240 }
];

const optimized = [];

try {
  const files = fs.readdirSync(originalsDir).filter(f => f.endsWith('.jpg') || f.endsWith('.png'));

  for (const file of files) {
    const inputPath = path.join(originalsDir, file);
    const baseName = path.parse(file).name;

    for (const variant of variants) {
      const outputFile = `${baseName}_${variant.suffix}.webp`;
      const outputPath = path.join(optimizedDir, outputFile);

      try {
        await sharp(inputPath)
          .resize(variant.width, variant.height, { fit: 'cover' })
          .webp({ quality: 85 })
          .toFile(outputPath);

        optimized.push({
          original: file,
          variant: variant.suffix,
          output: outputFile,
          width: variant.width,
          height: variant.height
        });
      } catch (e) {
        optimized.push({ original: file, variant: variant.suffix, error: e.message });
      }
    }
  }
} catch (err) {
  // Continue with empty optimized list
}

return [{ json: { ...data, optimized_images: optimized, optimized_count: optimized.filter(o => !o.error).length } }];

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const { place_id, industry, output_dir, brand_colors, downloaded, unsplash_photos, optimized_images, total_photos, optimized_count } = data;

const manifest = {
  place_id,
  industry,
  generated_at: new Date().toISOString(),
  brand_colors,
  originals: [
    ...(downloaded || []).filter(d => !d.error).map(d => ({ ...d })),
    ...(unsplash_photos || []).filter(p => !p.error).map(p => ({ ...p }))
  ],
  optimized: (optimized_images || []).filter(o => !o.error),
  stats: {
    total_originals: total_photos || 0,
    total_optimized: optimized_count || 0,
    variants: ['hero', 'card', 'thumb']
  }
};

fs.writeFileSync(
  path.join(output_dir, 'image-manifest.json'),
  JSON.stringify(manifest, null, 2)
);

return [{
  json: {
    status: 'success',
    place_id,
    output_dir,
    brand_colors,
    total_originals: total_photos || 0,
    total_optimized: optimized_count || 0
  }
}];

